/* BTCarousel — Figma 2344-1404 (D-Carousel).
 * Two variants: horizontal (left/right nav) and vertical (up/down nav).
 * Shared between Vue and React.
 *
 * Architecture:
 *   .bt-carousel                      root flex container
 *   .bt-carousel--horizontal          row layout
 *   .bt-carousel--vertical            column layout
 *   .bt-carousel--ready               enables CSS transition (added after first paint)
 *   .bt-carousel__viewport            overflow:hidden clipping window
 *   .bt-carousel__track               the sliding flex container
 *   .bt-carousel__slide               individual slide (BTCarouselItem)
 *   .bt-carousel__btn                 nav button (prev / next)
 *   .bt-carousel__btn--prev           prev direction
 *   .bt-carousel__btn--next           next direction
 *   .bt-carousel__indicators          dot row — absolute inside viewport
 *   .bt-carousel__dot                 single indicator dot
 *   .bt-carousel__dot--active         active dot (wider + brand-primary)
 */

/* ── Root ─────────────────────────────────────────────────────────── */

.bt-carousel {
  display: flex;
  align-items: center;
  gap: var(--space-xs); /* Figma: spacing.xs */
  position: relative;
}

.bt-carousel--horizontal {
  flex-direction: row;
}

.bt-carousel--vertical {
  flex-direction: column;
  height: 100%;         /* fill parent — parent must set explicit height */
  align-items: stretch; /* viewport stretches to full width */
}

/* ── Viewport — overflow:hidden clipping window ─────────────────── */

.bt-carousel__viewport {
  flex: 1;
  overflow: hidden;
  min-width: 0;
  position: relative; /* anchor for indicator dots */
  cursor: grab;
}

.bt-carousel--dragging {
  user-select: none;
}

.bt-carousel--dragging .bt-carousel__viewport {
  cursor: grabbing;
}

/* ── Track — the sliding flex container ─────────────────────────── */

.bt-carousel__track {
  display: flex;
  gap: var(--space-xs);
  will-change: transform;
}

/* Transition enabled only after first paint (avoids initial flash) */
.bt-carousel--ready .bt-carousel__track {
  transition: transform 0.35s cubic-bezier(0.4, 0, 0.2, 1);
}

.bt-carousel--horizontal .bt-carousel__track {
  flex-direction: row;
}

.bt-carousel--vertical .bt-carousel__track {
  flex-direction: column;
}

/* ── Slide — individual item slot ───────────────────────────────── */

.bt-carousel__slide {
  flex: none;
  /* Width set via --_bt-carousel-slide-w CSS custom property (set from JS) */
  width: var(--_bt-carousel-slide-w, 100%);
  box-sizing: border-box;
  overflow: hidden; /* clip slide content to wrapper bounds */
}

.bt-carousel--vertical .bt-carousel__slide {
  width: 100%;
  height: var(--_bt-carousel-slide-h, auto);
}

/* ── Navigation button wrapper ───────────────────────────────────── */
/*
 * BTButton (secondary-light, sm, iconOnly) is used as the nav control.
 * The wrapper clips it to a full-pill circle and provides flex sizing.
 */

.bt-carousel__btn-wrap {
  flex-shrink: 0;
  display: inline-flex;
  border-radius: var(--radius-rd); /* clips inner BTButton background to circle */
  overflow: hidden;
}

/* Match inner BTButton's border-radius so its focus ring is also circular */
.bt-carousel__btn-wrap .bt-button {
  border-radius: var(--radius-rd);
}

/* Vertical: center nav wrappers horizontally */
.bt-carousel--vertical .bt-carousel__btn-wrap {
  align-self: center;
}

/* Vertical: allow viewport to shrink below its content height in flex column */
.bt-carousel--vertical .bt-carousel__viewport {
  min-height: 0;
}

/* RTL: flip horizontal chevrons */
[dir="rtl"] .bt-carousel--horizontal .bt-carousel__btn-wrap svg {
  transform: scaleX(-1);
}

/* ── Dot indicators — absolute inside viewport ───────────────────── */

.bt-carousel__indicators {
  position: absolute;
  bottom: var(--space-sm);
  /* RTL-safe centering: span full width and use justify-content */
  left: 0;
  right: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--space-2xs);
  z-index: 10;
  pointer-events: none;
}

.bt-carousel__dot {
  flex-shrink: 0;
  height: 4px;
  border-radius: var(--radius-sm);
  background: var(--icon-tertiary);
  transition:
    width 0.22s cubic-bezier(0.4, 0, 0.2, 1),
    background 0.22s ease;
  width: 4px;
}

.bt-carousel__dot--active {
  width: 12px;
  background: var(--color-brand-primary);
}

/**
 * BTCarousel — horizontal or vertical sliding carousel.
 * Figma: node 2344-1404 (D-Carousel).
 * Web only — no Flutter implementation shares this file.
 *
 * Composes:
 *   BTCarouselItem — individual slide wrapper (children of this component).
 *
 * @example
 * ```tsx
 * const [idx, setIdx] = useState(0);
 *
 * <BTCarousel variant="horizontal" activeIndex={idx} onActiveIndexChange={setIdx}>
 *   <BTCarouselItem>
 *     <img src="/slide1.jpg" alt="Slide 1" />
 *   </BTCarouselItem>
 *   <BTCarouselItem>
 *     <img src="/slide2.jpg" alt="Slide 2" />
 *   </BTCarouselItem>
 * </BTCarousel>
 * ```
 */
import './BTCarousel.css';
import { BTButton } from '../button/BTButton';
import React, {
  useCallback,
  useEffect,
  useRef,
  useState,
} from 'react';
import type { BTCarouselProps } from './BTCarousel.types';

// ── SVG icon paths (Material Icons, 24×24 viewBox) ───────────────────
const ICON_CHEVRON_LEFT =
  'M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z';
const ICON_CHEVRON_RIGHT =
  'M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z';
const ICON_ARROW_UP =
  'M7.41 15.41L12 10.83l4.59 4.58L18 14l-6-6-6 6z';
const ICON_ARROW_DOWN =
  'M7.41 8.59L12 13.17l4.59-4.58L18 10l-6 6-6-6 1.41-1.41z';

const GAP_PX      = 4;  // matches .bt-carousel__track gap
const PEEK_PX     = 32; // horizontal: pixels visible on each side (left + right)
const PEEK_BOTTOM = 32; // vertical: pixels of next slide visible at bottom only

export function BTCarousel({
  variant = 'horizontal',
  activeIndex: controlledIndex,
  initialIndex = 0,
  loop = false,
  showButtons = true,
  showIndicators = true,
  autoPlay = false,
  autoPlayInterval = 3000,
  onActiveIndexChange,
  children,
}: BTCarouselProps) {
  const isHorizontal = variant === 'horizontal';

  // ── Controlled / uncontrolled index ────────────────────────────────
  const [internalIndex, setInternalIndex] = useState(initialIndex);
  const activeIndex =
    controlledIndex !== undefined ? controlledIndex : internalIndex;

  const slideCount = React.Children.count(children);

  function goTo(next: number) {
    let target = next;
    if (loop) {
      target = ((next % slideCount) + slideCount) % slideCount;
    } else {
      target = Math.max(0, Math.min(slideCount - 1, next));
    }
    if (target === activeIndex) return;
    setInternalIndex(target);
    onActiveIndexChange?.(target);
  }

  const prev = () => goTo(activeIndex - 1);
  const next = () => goTo(activeIndex + 1);

  const atStart = !loop && activeIndex === 0;
  const atEnd = !loop && activeIndex >= slideCount - 1;

  // ── DOM refs ────────────────────────────────────────────────────────
  const rootRef     = useRef<HTMLDivElement>(null);
  const viewportRef = useRef<HTMLDivElement>(null);
  const trackRef    = useRef<HTMLDivElement>(null);

  // ── RTL detection ────────────────────────────────────────────────────
  const [rtl, setRtl] = useState(false);
  useEffect(() => {
    const check = () =>
      setRtl(!!rootRef.current && getComputedStyle(rootRef.current).direction === 'rtl');
    check();
    const obs = new MutationObserver(check);
    obs.observe(document.documentElement, { attributes: true, attributeFilter: ['dir'] });
    return () => obs.disconnect();
  }, []);

  // ── Slide size (measured from viewport) ────────────────────────────
  const [slideW, setSlideW] = useState(0);
  const [slideH, setSlideH] = useState(0);

  const syncSize = useCallback(() => {
    const el = viewportRef.current;
    if (!el) return;
    if (isHorizontal) {
      // Horizontal: shrink slide width → peek on both left and right edges.
      const w = el.clientWidth - 2 * PEEK_PX;
      setSlideW(w);
      el.style.setProperty('--_bt-carousel-slide-w', `${w}px`);
      el.style.setProperty('--_bt-carousel-slide-h', `${el.clientHeight}px`); // unused but harmless
    } else {
      // Vertical: shrink slide height only at the bottom → peek of next slide only.
      // Slides start flush with the viewport top (no leading offset).
      const h = el.clientHeight - PEEK_BOTTOM;
      setSlideH(h);
      el.style.setProperty('--_bt-carousel-slide-h', `${h}px`);
      el.style.setProperty('--_bt-carousel-slide-w', `${el.clientWidth}px`); // unused (CSS overrides to 100%)
    }
  }, [isHorizontal]);

  // ── CSS transition readiness ────────────────────────────────────────
  const [ready, setReady] = useState(false);

  useEffect(() => {
    syncSize();
    const ro = new ResizeObserver(syncSize);
    if (viewportRef.current) ro.observe(viewportRef.current);
    // Allow first paint before enabling transition
    const t = requestAnimationFrame(() => setReady(true));
    return () => {
      ro.disconnect();
      cancelAnimationFrame(t);
    };
  }, [syncSize]);

  // ── Track transform ─────────────────────────────────────────────────
  const [dragOffset, setDragOffset] = useState(0);
  const [isDragging, setIsDragging] = useState(false);

  const slideSize = isHorizontal ? slideW : slideH;
  // Horizontal: +PEEK_PX offset so both left and right adjacent slides peek in.
  // Vertical: no leading offset — slides start flush at top; next slide peeks at bottom only.
  const baseOffset = isHorizontal
    ? PEEK_PX - activeIndex * (slideSize + GAP_PX)
    : -activeIndex * (slideSize + GAP_PX);
  const totalOffset = baseOffset + dragOffset;
  // RTL: flip horizontal track direction so slide 0 starts at the right
  const physicalOffset = isHorizontal && rtl ? -totalOffset : totalOffset;
  const axis = isHorizontal ? 'X' : 'Y';
  const trackStyle: React.CSSProperties = {
    transform: `translate${axis}(${physicalOffset}px)`,
    transition: isDragging || !ready ? 'none' : undefined,
  };

  // ── Auto-play ───────────────────────────────────────────────────────
  const [isPaused, setIsPaused] = useState(false);

  // Refs hold latest values so the interval callback never goes stale.
  const isPausedRef   = useRef(false);
  const isDraggingRef = useRef(false);
  const atEndRef      = useRef(false);
  const nextFnRef     = useRef<() => void>(next);

  // Keep refs in sync every render (cheap — no re-render cost).
  isPausedRef.current   = isPaused;
  isDraggingRef.current = isDragging;
  atEndRef.current      = atEnd;
  nextFnRef.current     = next;

  useEffect(() => {
    if (!autoPlay) return;
    const id = setInterval(() => {
      if (isPausedRef.current || isDraggingRef.current || atEndRef.current) return;
      nextFnRef.current();
    }, autoPlayInterval);
    return () => clearInterval(id);
  }, [autoPlay, autoPlayInterval]);

  // ── Touch gesture (swipe) ───────────────────────────────────────────
  const touchStartRef = useRef({ x: 0, y: 0 });
  const mouseStartRef = useRef({ x: 0, y: 0 });
  const dragOffsetRef = useRef(0);
  const prevFnRef = useRef<() => void>(prev);
  prevFnRef.current = prev;
  dragOffsetRef.current = dragOffset;

  function onTouchStart(e: React.TouchEvent) {
    const touch = e.touches[0];
    if (!touch) return;
    touchStartRef.current = { x: touch.clientX, y: touch.clientY };
    setIsDragging(true);
  }

  function onTouchMove(e: React.TouchEvent) {
    const touch = e.touches[0];
    if (!touch) return;
    const dx = touch.clientX - touchStartRef.current.x;
    const dy = touch.clientY - touchStartRef.current.y;
    // RTL: flip horizontal drag so swipe-right = next
    setDragOffset(isHorizontal ? (rtl ? -dx : dx) : dy);
  }

  function onTouchEnd() {
    const threshold = 30;
    if (dragOffset < -threshold) next();
    else if (dragOffset > threshold) prev();
    setDragOffset(0);
    setIsDragging(false);
  }

  // ── Mouse drag ──────────────────────────────────────────────────────
  function onMouseDown(e: React.MouseEvent) {
    if (e.button !== 0) return;
    mouseStartRef.current = { x: e.clientX, y: e.clientY };
    setIsDragging(true);

    function handleMouseMove(ev: MouseEvent) {
      const dx = ev.clientX - mouseStartRef.current.x;
      const dy = ev.clientY - mouseStartRef.current.y;
      const offset = isHorizontal ? (rtl ? -dx : dx) : dy;
      dragOffsetRef.current = offset;
      setDragOffset(offset);
    }

    function handleMouseUp() {
      const offset = dragOffsetRef.current;
      const threshold = 30;
      if (offset < -threshold) nextFnRef.current();
      else if (offset > threshold) prevFnRef.current();
      dragOffsetRef.current = 0;
      setDragOffset(0);
      setIsDragging(false);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    }

    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);
  }

  // ── Mouse wheel ─────────────────────────────────────────────────────
  const wheelTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  function onWheel(e: React.WheelEvent) {
    e.preventDefault();
    if (wheelTimeoutRef.current) return; // throttle: one slide per scroll burst
    const raw = isHorizontal ? (e.deltaX || e.deltaY) : e.deltaY;
    // RTL: flip scroll direction for horizontal
    const delta = isHorizontal && rtl ? -raw : raw;
    if (delta > 0) next();
    else if (delta < 0) prev();
    wheelTimeoutRef.current = setTimeout(() => {
      wheelTimeoutRef.current = null;
    }, 400);
  }

  // ── Prev/next icon paths ────────────────────────────────────────────
  const prevIconPath = isHorizontal ? ICON_CHEVRON_LEFT : ICON_ARROW_UP;
  const nextIconPath = isHorizontal ? ICON_CHEVRON_RIGHT : ICON_ARROW_DOWN;

  const rootClass = [
    'bt-carousel',
    `bt-carousel--${variant}`,
    ready ? 'bt-carousel--ready' : '',
    isDragging ? 'bt-carousel--dragging' : '',
  ]
    .filter(Boolean)
    .join(' ');

  return (
    <div
      ref={rootRef}
      className={rootClass}
      onMouseEnter={autoPlay ? () => setIsPaused(true)  : undefined}
      onMouseLeave={autoPlay ? () => setIsPaused(false) : undefined}
    >

      {/* ── Prev button ──────────────────────────────────────────── */}
      {showButtons && (
        <div className="bt-carousel__btn-wrap">
          <BTButton
            variant="secondary-light"
            size="small"
            iconOnly
            disabled={atStart}
            aria-label={isHorizontal ? 'Previous slide' : 'Previous'}
            onClick={prev}
          >
            <svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
              <path d={prevIconPath} />
            </svg>
          </BTButton>
        </div>
      )}

      {/* ── Viewport + track ─────────────────────────────────────── */}
      <div
        ref={viewportRef}
        className="bt-carousel__viewport"
        onMouseDown={onMouseDown}
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onTouchEnd}
        onWheel={onWheel}
      >
        <div ref={trackRef} className="bt-carousel__track" style={trackStyle}>
          {children}
        </div>

        {/* ── Dot indicators ─────────────────────────────────────── */}
        {showIndicators && slideCount > 1 && (
          <div className="bt-carousel__indicators" aria-hidden="true">
            {Array.from({ length: slideCount }, (_, i) => (
              <span
                key={i}
                className={[
                  'bt-carousel__dot',
                  i === activeIndex ? 'bt-carousel__dot--active' : '',
                ]
                  .filter(Boolean)
                  .join(' ')}
              />
            ))}
          </div>
        )}
      </div>

      {/* ── Next button ──────────────────────────────────────────── */}
      {showButtons && (
        <div className="bt-carousel__btn-wrap">
          <BTButton
            variant="secondary-light"
            size="small"
            iconOnly
            disabled={atEnd}
            aria-label={isHorizontal ? 'Next slide' : 'Next'}
            onClick={next}
          >
            <svg viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
              <path d={nextIconPath} />
            </svg>
          </BTButton>
        </div>
      )}

    </div>
  );
}

BTCarousel.displayName = 'BTCarousel';

/**
 * BTCarousel public API types.
 *
 * Figma: node 2344-1404 (D-Carousel).
 * Web only for this file (Vue shares via BTCarousel.types.ts in its own folder).
 */
import type React from 'react';

export type BTCarouselVariant = 'horizontal' | 'vertical';

export interface BTCarouselProps {
  /**
   * Layout direction.
   * - `'horizontal'` — left/right navigation (default)
   * - `'vertical'`   — up/down navigation
   * @default 'horizontal'
   */
  variant?: BTCarouselVariant;

  /**
   * Controlled active slide index.
   * When provided, the carousel is controlled — pair with `onActiveIndexChange`.
   */
  activeIndex?: number;

  /**
   * Initial active slide index for uncontrolled mode.
   * @default 0
   */
  initialIndex?: number;

  /**
   * Loop back to the first/last slide when reaching the boundary.
   * @default false
   */
  loop?: boolean;

  /**
   * Show previous/next navigation buttons.
   * @default true
   */
  showButtons?: boolean;

  /**
   * Show dot indicator row.
   * @default true
   */
  showIndicators?: boolean;

  /**
   * Automatically advance to the next slide on a timer.
   * Pauses while the pointer is over the carousel or during a swipe.
   * @default false
   */
  autoPlay?: boolean;

  /**
   * Milliseconds between auto-advances. Only used when `autoPlay` is `true`.
   * @default 3000
   */
  autoPlayInterval?: number;

  /** Slide content — must be one or more `BTCarouselItem` elements. */
  children?: React.ReactNode;

  /** Called when the active slide index changes (controlled + uncontrolled). */
  onActiveIndexChange?: (index: number) => void;
}

export interface BTCarouselItemProps {
  /** Content rendered inside the slide. */
  children?: React.ReactNode;
  /** Optional CSS class added to the slide wrapper. */
  className?: string;
}

/**
 * BTCarouselItem — individual slide wrapper for BTCarousel.
 *
 * Must be a direct child of BTCarousel.
 *
 * @example
 * ```tsx
 * <BTCarouselItem>
 *   <img src="/photo.jpg" alt="Photo" style={{ width: '100%', height: '200px', objectFit: 'cover' }} />
 * </BTCarouselItem>
 * ```
 */
import type { BTCarouselItemProps } from './BTCarousel.types';

export function BTCarouselItem({ children, className }: BTCarouselItemProps) {
  return (
    <div className={['bt-carousel__slide', className].filter(Boolean).join(' ')}>
      {children}
    </div>
  );
}

BTCarouselItem.displayName = 'BTCarouselItem';

export { BTCarousel } from './BTCarousel';
export { BTCarouselItem } from './BTCarouselItem';
export type {
  BTCarouselProps,
  BTCarouselItemProps,
  BTCarouselVariant,
} from './BTCarousel.types';
